ComponentDefinition.Script:
result.variables = {
    customerType: input.customerCode
}

result.query = `query MyQuery($customerType: String!) {
    mapping:lps_corporate_loan_mas_corp_assessment_mapping(where: {customer_type: {_eq: $customerType}}) {
    account_group
    account_type
    csr_weight
    crr_weight
    customer_status
    form_group
    formula_code
    isic_group
    occupation_agricultural
    prefix_debt
    summary_crr_code
    summary_csr_code
    total_debt
    assessment_type
  }
}
`;

const queryConditionResult = globalVariables.selectMapping ?? globalVariables.mapping[0]

result.variables = {
  form_group: queryConditionResult.form_group,
  summary_code: [queryConditionResult.summary_crr_code ?? '' , queryConditionResult.summary_csr_code ?? ''],
  formula_code: queryConditionResult.formula_code ?? ''
};

result.query = `query MyQuery ($form_group:String!,$summary_code:[String],$formula_code:String) {
  form:lps_corporate_loan_mas_corp_assessment_form(where: {form_group: {_eq: $form_group}}) {
    form_code
    form_group
    is_form_base
    property
  }
  summary:lps_corporate_loan_mas_corp_assessment_summary(where: {summary_code:{_in:$summary_code}}) {
    summary_code
  }
  formulaCSR:lps_corporate_loan_mas_corp_assessment_csr_formula(where:{formula_code:{_eq:$formula_code}}){
    formula_code
    pass_score
    score
  }
}`;

ProcessOutputScript.Script:
let formList = steps.AdwQueryFormAndSummary.data.form
let sectionList = steps.AdwQuerySectionAndSummarySection.data.section
let summarySectionList = steps.AdwQuerySectionAndSummarySection.data.summarySection
let summaryTopicList = steps.AdwQueryTopicAndSummaryTopic.data.summaryTopic
let criteriaCRRList = steps.AdwQueryOptionAndSummaryCriteria.data.criteriaCRR
let criteriaCSRList = steps.AdwQueryOptionAndSummaryCriteria.data.criteriaCSR
let topicList = steps.AdwQueryTopicAndSummaryTopic.data.topic
let optionList = steps.AdwQueryOptionAndSummaryCriteria.data.option
let optionSectionScoreList = steps.AdwQueryOptionAndSummaryCriteria.data.optionSectionScore
const querySectionCalculateResult = steps.AdwQueryTopicAndSummaryTopic.data.sectionCalculate
let setTopicList = []
const queryConditionResult = globalVariables.selectMapping ?? globalVariables.mapping[0]
const isExist = globalVariables?.isExist
const factorCSRList = steps.AdwQueryOptionAndSummaryCriteria.data.factorCSR
const formSelect = globalVariables.selectForm ?? steps.AdwQueryFormAndSummary.data.form[0].form_code

if (globalVariables.selectForm) {
    const baseFormCode = formList.filter((value) => value.is_form_base)[0].form_code
    const insectSectionList = sectionList.filter((value) => value.form_code == globalVariables.selectForm)
    const insectTopicList = topicList.filter((value) => value.form_code == globalVariables.selectForm)
    const insectOptionList = optionList.filter((value) => value.form_code == globalVariables.selectForm)
    const insectOptionSectionScore = optionSectionScoreList.filter((value) => value.form_code == globalVariables.selectForm)
    const setSectionList = [...new Set(insectSectionList.map((item) => item.section_code))]
    setTopicList = [...new Set(insectTopicList.map((item) => ({topic_code: item.topic_code, section_code: item.section_code})))]
    const setOptionList = [...new Set(insectOptionList.map((item) => ({topic_code: item.topic_code, section_code: item.section_code, option_group:item.option_group})))]
    const setOptionSectionScoreList = [
        ...new Set(insectOptionSectionScore.map((item) => ({section_calculate_code: item.section_calculate_code, section_code: item.section_code,option_group:item.option_group}))),
    ]
    const baseOptionList = optionList.filter(
        (value) =>
            value.form_code == baseFormCode &&
            !setOptionList.find((val) => value.topic_code == val.topic_code && value.section_code == val.section_code && value.option_group == val.option_group)
    )
    const baseTopicList = topicList.filter(
        (value) =>
            value.form_code == baseFormCode &&
            !setTopicList.find((val) => value.topic_code == val.topic_code && value.section_code == val.section_code)
    )
    const baseSectionList = sectionList.filter((value) => value.form_code == baseFormCode && !setSectionList.includes(value.section_code))
    const baseOptionSectionScoreList = optionSectionScoreList.filter(
        (value) =>
            value.form_code == baseFormCode &&
            !setOptionSectionScoreList.find(
                (val) => value.section_calculate_code == val.section_calculate_code && value.section_code == val.section_code && value.option_group == val.option_group
            )
    )

    optionSectionScoreList = [...baseOptionSectionScoreList, ...insectOptionSectionScore]
    optionList = [...baseOptionList, ...insectOptionList]
    topicList = [...baseTopicList, ...insectTopicList].sort((valueA, valueB) => valueA.topic_seq - valueB.topic_seq)
    sectionList = [...baseSectionList, ...insectSectionList]
}

// condition to hide a section CSR

const listOfIncludeSectionCSR =
    formList.find((value) => value.form_code == formSelect && value.property?.conditionRender)?.property?.conditionRender?.factorNameIncludeCSR ?? []

let variablesOtherConditionList = []

if (listOfIncludeSectionCSR.length > 0) {
    const factorList = factorCSRList.map((value) => value.factor_name)
    const listTopic = [
        ...new Set(
            listOfIncludeSectionCSR
                .filter((value) => factorList.includes(value.name))
                .map((value) => value.list)
                .flat()
        ),
    ]
    sectionList = sectionList.filter((value) => value.section_type == 'CRR' || listTopic.find((topic) => topic.section == value.section_code))
    let sectionListTemp = sectionList.map((value) => ({sectionCode: value.section_code, sectionType: value.section_type}))
    topicList = topicList.filter(
        (value) =>
            sectionListTemp.find((vals)=> vals.sectionType == 'CRR' && value.section_code == vals.sectionCode) ||
            listTopic.find((topic) => topic.topic == value.topic_code && topic.section == value.section_code)
    )
    const topicTempList = topicList.map((value) => value.topic_code)
    sectionListTemp = sectionList.map((value) => value.section_code)
    optionList = optionList.filter((value) => topicTempList.includes(value.topic_code) && sectionListTemp.includes(value.section_code))

    variablesOtherConditionList = topicList.filter((value)=> value?.property?.refVariable).reduce((acc,value)=> {
    if(value?.property?.refVariable){
        acc.push(value?.property?.refVariable)
    }
    return acc
},[])

} else if(queryConditionResult.form_group == 'FG_1' || queryConditionResult.form_group == 'FG_19' ) {
    sectionList = sectionList.filter((value) => value.section_type != 'CSR')
    const sectionListTemp = sectionList.map((value) => value.section_code)
    topicList = topicList.filter((value) => sectionListTemp.includes(value.section_code))
    const topicTempList = topicList.map((value) => value.topic_code)
    optionList = optionList.filter((value) => topicTempList.includes(value.topic_code) && sectionListTemp.includes(value.section_code))
}

// filter varaible using
let factorFormulaList = querySectionCalculateResult
    .map((item) => item.formula)
    .reduce((acc, value) => {
        const factorList = value.match(/FC_(\d+)/g)
        if (factorList) {
            acc = [...new Set([...acc, ...factorList])]
        }
        return acc
    }, [])

const factorCRR = steps.AdwQueryOptionAndSummaryCriteria.data.factorCRR.filter(
    (value) => topicList.find((topicValue) => value.factor_code == topicValue.factor_code) || factorFormulaList.includes(value.factor_code)
)
const variableCSR = steps.AdwQueryOptionAndSummaryCriteria.data.factorCSR.map((value) => value.variable_code).flat()
const variableCRR = factorCRR.map((value) => value.variable_code).flat()
let variableList = [] 

if(queryConditionResult.crr_weight != null && queryConditionResult.csr_weight == null){
    variableList = [...new Set([...variableCRR])].filter((item) => item != null)
}else if(queryConditionResult.crr_weight == null && queryConditionResult.csr_weight != null){
    variableList = [...new Set([...variablesOtherConditionList, ...variableCSR])].filter((item) => item != null)
}else if (queryConditionResult.crr_weight != null && queryConditionResult.csr_weight != null){
    variableList = [...new Set([...variablesOtherConditionList,...variableCRR, ...variableCSR])].filter((item) => item != null)
}

// fix topic with codition
topicList = topicList.map((value) => {
    if (value.property?.condition) {
        let objects = value.property?.condition?.find((value) => value.customerType == input.customerCode)
        value.property = {...objects,...objects.property,condition:value.property.condition}
    }
    return value
})

let integrateCodeFilterOut = ['LOAN', 'LOAN_REQUEST_HEADER', 'CAP', 'CAP_INVESTMENT', 'CMS', 'CMS_JURISTIC']
let variableCRRListFilter = steps.AdwQueryVariable.data.variable.filter((value) => variableList.includes(value.variable_code))

if (input?.isInCBS) {
    variableCRRListFilter = variableCRRListFilter.filter(item => 
      !(integrateCodeFilterOut.includes(item.integrate_code) && globalVariables.variableCRR.includes(item.variable_code))
    )
}

if (["CREATE_LOAN","CHANGE_LOAN","OVERDRAFT"].includes(input.assessmentType) && (steps.AdwQueryProductMaxtrix?.data?.listsNullType?.length > 0 || steps.AdwQueryProductMaxtrix?.data?.listsOtherType?.length > 0) && queryConditionResult?.form_group == 'FG_1' && queryConditionResult?.crr_weight != null) {
    variableCRRListFilter = variableCRRListFilter.filter(item => 
      !(["FIN","CAP"].includes(item.integrate_code) && globalVariables.variableCRR.includes(item.variable_code))
    )
}


// mapping output
return (output = {
    status: steps.LookupStatus,
    data:  {
              formSelect: formSelect,
              isMultiForm: globalVariables.isMultiForm,
              option: optionList,
              optionSectionScore: optionSectionScoreList,
              topic: topicList,
              section: sectionList,
              form: formList,
              mapping: globalVariables.selectMapping ?? globalVariables.mapping[0],
              summary: steps.AdwQueryFormAndSummary.data.summary,
              summarySection: summarySectionList,
              summaryTopic: summaryTopicList,
              criteriaCRR: criteriaCRRList,
              criteriaCSR: criteriaCSRList,
              sectionCalculate: steps.AdwQueryTopicAndSummaryTopic.data.sectionCalculate,
              factorCRR,
              factorCSR: factorCSRList,
              formulaCSR: steps.AdwQueryFormAndSummary.data.formulaCSR,
              variable: variableCRRListFilter,
          }
})

ComponentDefinition.Script:
const queryTopicResult = steps.AdwQueryTopicAndSummaryTopic.data.topic const querySummarySectionResult = steps.AdwQuerySectionAndSummarySection.data.summarySection const queryFormResult = steps.AdwQueryFormAndSummary.data.form const querySectionCalculateResult = steps.AdwQueryTopicAndSummaryTopic.data.sectionCalculate const list = queryTopicResult.map(item => item.topic_code); const formulaCSR = steps.AdwQueryFormAndSummary?.data?.formulaCSR?.[0]?.formula_code ?? ''
let sectionCalculateCodeList = [...new Set(querySectionCalculateResult.map(item => item.section_calculate_code))]
let factorFormulaList = querySectionCalculateResult.map(item => item.formula).reduce((acc, value) => { const factorList = value.match(/FC_(\d+)/g) if (factorList) { acc = [...new Set([...acc, ...factorList])] } return acc }, [])
let factorCodeList = [...new Set([...queryTopicResult.map(item => item.factor_code).filter(item=>item != null),...factorFormulaList])]; let FormList = [...new Set(queryFormResult.map(item => item.form_code))]; let groupCriteriaList = [...new Set(querySummarySectionResult.map(item => item.group_criteria_code || ''))]; if(globalVariables.selectForm){ FormList = queryFormResult.filter((value)=>value.is_form_base || value.form_code === globalVariables.selectForm).map((value)=>value.form_code) }
result.variables = { topic_code: list, form_code: FormList, group_criteria_code:groupCriteriaList, factor_code: factorCodeList, section_calculate_code: sectionCalculateCodeList, formula_code: formulaCSR };
result.query = `query MyQuery($form_code:[String]!, $topic_code: [String]!,$group_criteria_code:[String]!,$factor_code:[String]!,$section_calculate_code:[String]!, $formula_code:String) { option:lps_corporate_loan_mas_corp_assessment_option(order_by: {option_seq: asc},where: {form_code: {_in: $form_code}, topic_code: {_in: $topic_code}}) { form_code max_range min_range option_input_type option_seq option_group score section_code topic_code section_calculate_code } optionSectionScore:lps_corporate_loan_mas_corp_assessment_option(order_by: {option_seq: asc},where: {form_code: {_in: $form_code}, section_calculate_code: {_in: $section_calculate_code}}) { form_code max_range min_range option_input_type option_seq option_group score section_code topic_code section_calculate_code } criteriaCRR:lps_corporate_loan_mas_corp_assessment_crr_criteria(where: {group_criteria_code: {_in: $group_criteria_code}}){ criteria_code criteria_id group_criteria_code maximum_score minimum_score result_grade isPass condition } factorCRR:lps_corporate_loan_mas_corp_assessment_crr_factor(where: {factor_code: {_in: $factor_code }}) { condition_code factor_code factor_id factor_name formula variable_code } factorCSR:lps_corporate_loan_mas_corp_assessment_csr_factor(where:{formula_code:{_eq: $formula_code}}) { coefficient condition_code description factor_code factor_id factor_name formula formula_code max min variable variable_code } criteriaCSR:lps_corporate_loan_mas_corp_assessment_csr_criteria(where:{formula_code:{_eq: $formula_code}}) { criteria_code criteria_id formula_code grade grade_desc interest_rate_spread interest_rate_type isPass maximum_pd maximum_score minimum_pd minimum_score result_desc prefix } } `;

ProcessOutputScript.Script:
let filter = ''

steps.AdwQueryFormAndSummary.data.form.forEach((value) => {
    if (value.property) {
        if (value.property.businessType && value.property.businessType.includes(input.bussinessType)) {
            filter = value.form_code
        }
        if (value.property.customerCode && value.property.customerCode.includes(input.customerCode)) {
            filter = value.form_code
        }
        if (
            value.property.groupType &&
            value.property.groupType.includes(input.groupType) &&
            value.property.accountType &&
            value.property.accountType.includes(input.accountType)
        ) {
            filter = value.form_code
        }
        if (
            value.property.groupType &&
            value.property.groupType.includes(input.groupType) &&
            !value.property.accountType &&
            input.accountType != '8100'
        ) {
            filter = value.form_code
        }
        if (value.property.isMultiForm) {
            globalVariables.isMultiForm = true
        }
    }
})

globalVariables.selectForm = filter

ComponentDefinition.Script:
const querySectionResult = steps.AdwQuerySectionAndSummarySection.data.section
const querySummarySectionResult = steps.AdwQuerySectionAndSummarySection.data.summarySection
const queryFormResult = steps.AdwQueryFormAndSummary.data.form
const SectionList = [...new Set(querySectionResult.map(item => item.section_code))];
// const SummarySectionList = [...new Set(querySummarySectionResult.map(item => item.summary_section_code))];
const SummarySectionList = [...new Set(
  querySummarySectionResult
    .filter(item => item.summary_section_code !== null && item.summary_section_code !== undefined)
    .map(item => item.summary_section_code)
)];
let FormList = [...new Set(queryFormResult.map(item => item.form_code))];
if(globalVariables.selectForm){
    FormList = queryFormResult.filter((value)=>value.is_form_base || value.form_code === globalVariables.selectForm).map((value)=>value.form_code)
}

result.variables = {
  section_code: SectionList,
  form_code: FormList,
  SummarySectionList: SummarySectionList
};

result.query = `query MyQuery ($section_code:[String]!,$form_code:[String]!,$SummarySectionList:[String]!) {
  topic:lps_corporate_loan_mas_corp_assessment_topic(order_by: {topic_seq: asc,section_code:asc},where: {form_code: {_in: $form_code}, section_code: {_in: $section_code}}) {
    form_code
    property
    section_code
    topic_code
    topic_seq
    factor_code
  }
  summaryTopic:lps_corporate_loan_mas_corp_assessment_summary_topic(order_by: {summary_topic_seq: asc},where:{summary_section_code:{_in:$SummarySectionList}}) {
    summary_section_code
    summary_topic_code
    summary_topic_seq
    summary_topic_input_type
    summary_topic_type
    topic_group
    uom_text
    name
  }
  sectionCalculate:lps_corporate_loan_mas_corp_assessment_section_calculate(where: {section_code: {_in: $section_code},form_code:{_in:$form_code}}){
    formula
    section_calculate_code
    section_calculate_id
    section_code
    form_group
    form_code
  }
}`;

const queryConditionResult = globalVariables.selectMapping ?? globalVariables.mapping[0]

const queryFormResult = steps.AdwQueryFormAndSummary.data.form
const querySummaryResult = steps.AdwQueryFormAndSummary.data.summary
let summaryList = [...new Set(querySummaryResult.map(item => item.summary_code))];

let FormList = [...new Set(queryFormResult.map(item => item.form_code))];
if(globalVariables.selectForm){
    FormList = queryFormResult.filter((value)=>value.is_form_base || value.form_code === globalVariables.selectForm).map((value)=>value.form_code)
}

result.variables = {
  form_group: queryConditionResult.form_group,
  form_code: FormList,
  summary_code: summaryList
};

result.query = `query MyQuery ($form_code:[String]!,$form_group:String,$summary_code:[String]) {
  section:lps_corporate_loan_mas_corp_assessment_section(order_by: {section_seq: asc}, where: {form_group: {_eq: $form_group},form_code:{_in:$form_code}}) {
    form_code
    property
    section_code
    section_seq
    section_type
  }
  summarySection:lps_corporate_loan_mas_corp_assessment_summary_section(order_by: {summary_section_id: asc},where: {summary_code: {_in: $summary_code}}) {
    group_criteria_code
    is_sum
    section_code
    summary_code
    summary_section_code
    section_type
    condition
    is_show
    sections
  }
}`;

