ComponentDefinition.Script:
const queryFactorCRRResult = steps.AdwQueryOptionAndSummaryCriteria?.data?.factorCRR ?? []
const queryFactorCSRResult = steps.AdwQueryOptionAndSummaryCriteria?.data?.factorCSR ?? []
const variableCRRList = [...new Set((queryFactorCRRResult.reduce((accumulator,currentValue)=>
{
    if(!currentValue.variable_code) return accumulator
    return [ ...currentValue.variable_code,...accumulator]
},[])))];
const variableCSRList = [...new Set((queryFactorCSRResult.reduce((accumulator,currentValue)=>{
    if(!currentValue.variable_code) return accumulator
    return [ ...currentValue.variable_code,...accumulator]
},[])))];

const topic = steps.AdwQueryTopicAndSummaryTopic?.data?.topic ?? []
const topicVariable = topic.filter((value)=> value?.property?.refVariable).reduce((acc,value)=> {
    if(value?.property?.refVariable){
        acc.push(value?.property?.refVariable)
    }
    return acc
},[])

globalVariables.variableCRR = variableCRRList

result.variables = {
    variable_code: [...new Set([...variableCRRList,...variableCSRList, ...topicVariable])]
};

result.query = `query MyQuery($variable_code:[String]!) {
  variable:lps_corporate_loan_mas_corp_assessment_variable(where: {variable_code: {_in: $variable_code }}) {
    condition_code
    variable_code
    integrate_code
  }
}
`;

ProcessOutputScript.Script:
const mapping = globalVariables.mapping
const item = steps.AdwQueryAgricultural.data.master_mas_agricultural_p[0]
const agricultural    = item?.occupation_agricultural === true
const nonAgricultural = item?.occupation_agricultural !== true
const defaultNonAgricultural = !agricultural && !nonAgricultural

const backendParamCrrCsr = steps.backend_parameter_CRR_CSR.data.result
let backendParamConfig = backendParamCrrCsr.find(data => data.key_name === 'CRR_CSR_HIDE_SECTION')
let arrayJsonBackendParamConfig = backendParamConfig.key_json_value

//filter customerStatus new,old,all & check total_debt 

const perFilter = mapping.filter((value)=>{
    let isCheck = value.total_debt == null
    if(value.total_debt && value.prefix_debt){
        if(value.prefix_debt == "<="){
            isCheck = input.loanAmount <= value.total_debt
        }else if(value.prefix_debt == ">"){
            isCheck = input.loanAmount > value.total_debt
        }
    }
    return (value.customer_status == input.customerStatus || value.customer_status == null) && isCheck
})

//filter by purpose

const filterByAccountType = perFilter.filter((value)=> value.account_type == input.accountType)
const filterByAccountGroup = perFilter.filter((value)=> value.account_group == input.accountGroup && value.account_group == "LN")
const filterByAgriCultural = perFilter.filter(
    (value)=> value.account_group == "COM" 
    && value.occupation_agricultural == true 
    && (value.isic_group && value.isic_group.includes(item?.formula_name ?? "")) 
    && agricultural
    )
const filterByNonAgriCultural = perFilter.filter((value)=>  value.account_group == "COM" && value.occupation_agricultural == false && nonAgricultural)
const filterByAllCondition = perFilter.filter((value)=> value.account_group == null && value.account_type == null && value.occupation_agricultural == null)
const filterByDefaultNonAgricultural = perFilter.filter((value)=>  value.account_group == "COM" && value.occupation_agricultural == false && defaultNonAgricultural)

if (input.customerCode == '603' || input.customerCode == '600') {
    if (input.assessmentType == 'CREATE_LOAN' || input.assessmentType == 'CHANGE_LOAN' || input.assessmentType == 'OVERDRAFT') {
        let checkConfigMatch = arrayJsonBackendParamConfig.find(eachValue => JSON.stringify(eachValue) === JSON.stringify([Number(input.accountType),Number(input.accountSubType),Number(input.marketCode)]))
        if (
            checkConfigMatch != undefined
        ) {
            if (filterByAccountGroup.length > 0) {
                globalVariables.selectMapping = filterByAccountGroup[0]
                return filterByAccountGroup[0]
            } else if (filterByAccountType.length > 0) {
                globalVariables.selectMapping = filterByAccountType[0]
                return filterByAccountType[0]
            } else if (filterByAgriCultural.length > 0) {
                globalVariables.selectMapping = filterByAgriCultural[0]
                return filterByAgriCultural[0]
            } else if (filterByNonAgriCultural.length > 0) {
                globalVariables.selectMapping = filterByNonAgriCultural[0]
                return filterByNonAgriCultural[0]
            } else if (filterByDefaultNonAgricultural.length > 0) {
                globalVariables.selectMapping = filterByDefaultNonAgricultural[0]
                return filterByDefaultNonAgricultural[0]
            }
        } else {
            if (filterByAllCondition.length > 0) {
                globalVariables.selectMapping = filterByAllCondition[0]
                return filterByAllCondition[0]
            } else {
                throw new Error('not found')
            }
        }
    } else if (
        input.assessmentType == 'CREATE_DBM' ||
        input.assessmentType == 'CHANGE_DBM' ||
        input.assessmentType == 'AUTO_DBM'
    ) {
        if (input.accountType == '8200' || input.accountType == '8500') {
            if (filterByAgriCultural.length > 0) {
                globalVariables.selectMapping = filterByAgriCultural[0]
                return filterByAgriCultural[0]
            } else if (filterByNonAgriCultural.length > 0) {
                globalVariables.selectMapping = filterByNonAgriCultural[0]
                return filterByNonAgriCultural[0]
            } else if (filterByAllCondition.length > 0) {
                globalVariables.selectMapping = filterByAllCondition[0]
                return filterByAllCondition[0]
            } else if (filterByDefaultNonAgricultural.length > 0) {
                globalVariables.selectMapping = filterByDefaultNonAgricultural[0]
                return filterByDefaultNonAgricultural[0]
            }
        } else {
            if (filterByAllCondition.length > 0) {
                globalVariables.selectMapping = filterByAllCondition[0]
                return filterByAllCondition[0]
            } else {
                throw new Error('not found')
            }
        }
    }
}


if (filterByAccountGroup.length > 0) {
    globalVariables.selectMapping = filterByAccountGroup[0]
    return filterByAccountGroup[0]
} else if (filterByAccountType.length > 0) {
    globalVariables.selectMapping = filterByAccountType[0]
    return filterByAccountType[0]
} else if (filterByAgriCultural.length > 0) {
    globalVariables.selectMapping = filterByAgriCultural[0]
    return filterByAgriCultural[0]
} else if (filterByNonAgriCultural.length > 0) {
    globalVariables.selectMapping = filterByNonAgriCultural[0]
    return filterByNonAgriCultural[0]
} else if (filterByAllCondition.length > 0) {
    globalVariables.selectMapping = filterByAllCondition[0]
    return filterByAllCondition[0]
} else if (filterByDefaultNonAgricultural.length > 0) {
    globalVariables.selectMapping = filterByDefaultNonAgricultural[0]
    return filterByDefaultNonAgricultural[0]
} else {
    throw new Error('not found')
}

