const isic = input.isicCode.split("|")

function removeLeadingZeros(str) {
  return str.replace(/^0+/, '');
}

const isicLevel1 = removeLeadingZeros(isic[0])
const isicLevel2 = removeLeadingZeros(isic[1])
const isicLevel3 = removeLeadingZeros(isic[2])
const isicLevel4 = removeLeadingZeros(isic[3])
const isicLevel5 = removeLeadingZeros(isic[4])

