ProcessOutputScript.Script:
const mapping = globalVariables.mapping
const productMaxtrix = steps.AdwQueryProductMaxtrix.data.result
if (productMaxtrix.length == 0 || (productMaxtrix[0].crr_flag == 'N' && productMaxtrix[0].csr_flag == 'N')) {
    throw new Error('not found')
}

globalVariables.mapping = mapping.filter((value) => {
    if (productMaxtrix[0].crr_flag == 'Y' && productMaxtrix[0].csr_flag == 'Y') {
        return (
            (value.crr_weight != null && value.csr_weight != null) ||
            (value.crr_weight == null && value.csr_weight != null) ||
            (value.crr_weight != null && value.csr_weight == null)
        )
    } else if (productMaxtrix[0].crr_flag == 'Y' && productMaxtrix[0].csr_flag == 'N') {
        return value.crr_weight != null && value.csr_weight == null
    } else if (productMaxtrix[0].crr_flag == 'N' && productMaxtrix[0].csr_flag == 'Y') {
        return value.crr_weight == null && value.csr_weight != null
    }
    return false
})

return globalVariables.mapping

